#!/usr/bin/env python3
import re,base64,itertools,string
from collections import defaultdict

text=open('assignment.txt').read()
pre=text.split('Upon further investigation')[0]
blocks=re.findall(r'(?:[A-Za-z0-9+/]{20,}={0,2}\n?)+',pre)
cts=[]
for b in blocks:
    s=''.join(b.split())
    try:
        c=base64.b64decode(s,validate=True)
    except Exception:
        continue
    if len(c)>0:
        cts.append(c)
print(f'count={len(cts)}')
print('lengths=',[len(c) for c in cts])

# space heuristic: if ci^cj at pos gives alphabetic likely one side space
n=len(cts)
space_votes=[defaultdict(int) for _ in range(n)]
for i,j in itertools.combinations(range(n),2):
    x=bytes(a^b for a,b in zip(cts[i],cts[j]))
    for k,b in enumerate(x):
        if (65<=b<=90) or (97<=b<=122):
            space_votes[i][k]+=1
            space_votes[j][k]+=1

keystream={}
threshold=max(2,n//2)
for i in range(n):
    for k,v in space_votes[i].items():
        if v>=threshold and k < len(cts[i]):
            keystream[k]=cts[i][k]^0x20

# refine with common chars voting
common=b' etaoinshrdlucmfwypvbgkqjxzETAOINSHRDLU.,-\'"!?;:()0123456789{}_/\\@#*$%[]\n'
for k in range(max(len(c) for c in cts)):
    if k in keystream: continue
    best=None
    for ks in range(256):
        score=0
        ok=0
        for c in cts:
            if k>=len(c):
                continue
            p=c[k]^ks
            if p in common:
                score+=2
                ok+=1
            elif 32<=p<=126:
                score+=1
                ok+=1
            else:
                score-=3
        if best is None or score>best[0]:
            best=(score,ks,ok)
    if best and best[0]>0:
        keystream[k]=best[1]

for idx,c in enumerate(cts):
    out=[]
    for k,b in enumerate(c):
        if k in keystream:
            p=b^keystream[k]
            out.append(chr(p) if 32<=p<=126 else '?')
        else:
            out.append('?')
    print(f'[{idx:02d}]',''.join(out))

# save parsed ciphertexts as python literal
with open('parsed_cts.py','w') as f:
    f.write('cts = [\n')
    for c in cts:
        f.write(repr(c)+',\n')
    f.write(']\n')

